mapper.select:
SELECT wo.*, u.nickname AS assignee_name, pp.product_name AS plan_product_name FROM work_order wo LEFT JOIN user u ON wo.assignee_id = u.id LEFT JOIN production_plan pp ON wo.plan_id = pp.id
AND wo.status = #{status}
AND wo.assignee_id = #{assigneeId}
ORDER BY wo.create_time DESC

mapper.update:
UPDATE work_order
plan_id = #{planId}, product_name = #{productName}, quantity = #{quantity}, assignee_id = #{assigneeId}, process_requirement = #{processRequirement}, delivery_date = #{deliveryDate}, status = #{status}, actual_quantity = #{actualQuantity}, complete_time = #{completeTime},
WHERE id = #{id}
